import React, { useEffect, useState } from 'react';
import fileService from '../services/fileService';
function DownloadManager(){
  const [files,setFiles]=useState([]);
  useEffect(()=>{ (async()=>{ try{ const res = await fileService.getSharedFiles(); setFiles(res); }catch(e){ console.error(e); } })(); },[]);
  const download=async(id)=>{ try{ await fileService.downloadFile(id); alert('Downloaded'); }catch(e){ alert('Failed'); } };
  return (
    <div className="p-6">
      <h2 className="text-2xl font-bold mb-4">Files Shared With Me</h2>
      <table className="w-full bg-white"><thead><tr><th>File ID</th><th>Name</th><th>Owner</th><th>Role</th><th>Action</th></tr></thead>
      <tbody>{files.map(f=>(
        <tr key={f.file_id} className="border-t">
          <td className="p-2">{f.file_id}</td>
          <td className="p-2">{f.originalname}</td>
          <td className="p-2">{f.owner_email}</td>
          <td className="p-2">{f.role}</td>
          <td className="p-2">{(f.role==='download' || f.role==='share') ? <button onClick={()=>download(f.file_id)} className="bg-green-500 text-white px-2 py-1 rounded">Download</button> : 'Not allowed'}</td>
        </tr>
      ))}</tbody></table>
    </div>
  );
}
export default DownloadManager;
